#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard escapeHTML);

my $q = CGI->new;
my $log_dir = '/var/log';
my $filename = $q->param('logfile') || '';

print $q->header('text/html; charset=UTF-8');
print "<!DOCTYPE html><html><head><title>Log Viewer</title></head><body>";

if ($filename eq '') {
    print "<h1>No log file specified</h1>";
    print "</body></html>";
    exit;
}

print "<h1>Viewing Log: " . escapeHTML($filename) . "</h1>";
print "<pre>";

if (open(FH, "$log_dir/$filename")) {
    while (my $line = <FH>) {
        print escapeHTML($line);
    }
    close(FH);
} else {
    print escapeHTML("Could not open log file: $!");
}

print "</pre>";
print "</body></html>";